// Extrae y valida el id de la nota a eliminar
const body = $input.first().json.body || $input.first().json;

const id = (body.id || '').toString().trim();

if (!id) {
  throw new Error('El campo id es requerido');
}

// Validar formato UUID básico
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(id)) {
  throw new Error('El id debe ser un UUID válido');
}

return [{ json: { id } }];

const result = $input.first().json;

if (result.error) {
  throw new Error('Error al eliminar: ' + (result.error?.message || String(result.error)));
}

if (!result.id) {
  throw new Error('Nota no encontrada o ya estaba eliminada');
}

return [{ json: { id: result.id, deleted: true } }];
